// 1. Sadə Generic Sinif
class Store<T> {
  items: T[] = [];
  add(item: T): void {
    this.items.push(item);
  }
  getAll(): T[] {
    return this.items;
  }
}
const numberStore = new Store<number>();
numberStore.add(1);
numberStore.add(2);
console.log(numberStore.getAll()); // Çıxış: [1, 2]
const stringStore = new Store<string>();
stringStore.add("Apple");
console.log(stringStore.getAll()); // Çıxış: ["Apple"]

// 2. Generic ilə məhdudiyyətlər
class LengthStore<T extends { length: number }> {
  item: T;
  constructor(item: T) {
    this.item = item;
  }
  getLength(): number {
    return this.item.length;
  }
}
const stringLengthStore = new LengthStore<string>("Test");
console.log(stringLengthStore.getLength()); // Çıxış: 4
// const numberLengthStore = new LengthStore<number>(42); // Səhv: number-ın length xüsusiyyəti yoxdur

// 3. Çoxsaylı Generic tiplər
class Pair<K, V> {
  key: K;
  value: V;
  constructor(key: K, value: V) {
    this.key = key;
    this.value = value;
  }
  getPair(): [K, V] {
    return [this.key, this.value];
  }
}
const pair = new Pair<string, number>("Age", 25);
console.log(pair.getPair()); // Çıxış: ["Age", 25]

// 4. Default Generic tiplər
class Wrapper<T = string> {
  value: T;
  constructor(value: T) {
    this.value = value;
  }
  getValue(): T {
    return this.value;
  }
}
const stringWrapper = new Wrapper("Test"); // T avtomatik string olur
const numberWrapper = new Wrapper<number>(42);
console.log(stringWrapper.getValue()); // Çıxış: Test
console.log(numberWrapper.getValue()); // Çıxış: 42

// 5. Generic ilə union tipləri
type AllowedType = string | number;
class RestrictedStore<T extends AllowedType> {
  data: T;
  constructor(data: T) {
    this.data = data;
  }
  getData(): T {
    return this.data;
  }
}
const stringData = new RestrictedStore<string>("Hello");
const numberData = new RestrictedStore<number>(123);
console.log(stringData.getData()); // Çıxış: Hello
console.log(numberData.getData()); // Çıxış: 123
// const boolData = new RestrictedStore<boolean>(true); // Səhv: boolean AllowedType-a uyğun deyil

// 6. Generic Sinif ilə interfeyslər
interface Item<T> {
  id: string;
  data: T;
}
class Product<T> implements Item<T> {
  id: string;
  data: T;
  constructor(id: string, data: T) {
    this.id = id;
    this.data = data;
  }
  getDetails(): string {
    return `ID: ${this.id}, Data: ${this.data}`;
  }
}
const laptop = new Product<string>("P001", "Laptop");
console.log(laptop.getDetails()); // Çıxış: ID: P001, Data: Laptop

// 7. Generic Sinif ilə funksiyalar
function processItem<T>(item: Item<T>): string {
  return `Item ID: ${item.id}, Data: ${item.data}`;
}
const item: Item<number> = new Product<number>("I001", 999);
console.log(processItem(item)); // Çıxış: Item ID: I001, Data: 999

// Sadə mağaza sistemi
interface Product<T> {
  id: string;
  data: T;
}
class ProductStore<T> {
  products: Product<T>[] = [];
  add(id: string, data: T): void {
    this.products.push({ id, data });
  }
  getById(id: string): Product<T> | undefined {
    return this.products.find(p => p.id === id);
  }
}
const store = new ProductStore<string>();
store.add("P001", "Laptop");
store.add("P002", "Mouse");
console.log(store.getById("P001")); // Çıxış: { id: "P001", data: "Laptop" }

const numberStore = new ProductStore<number>();
numberStore.add("P003", 999);
console.log(numberStore.getById("P003")); // Çıxış: { id: "P003", data: 999 }

// Generic sinif ilə funksiya
function checkProduct<T>(product: Product<T>): string {
  return `Product ID: ${product.id}, Data: ${product.data}`;
}
const laptop: Product<string> = { id: "P001", data: "Laptop" };
console.log(checkProduct(laptop)); // Çıxış: Product ID: P001, Data: Laptop

